import { useState, useMemo } from "react";
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid, Cell, Legend } from "recharts";

const COEFF = 0.78;
const FORF_TAX = 0.15;
const INPS_GS = 0.2607;
const INPS_COMM_MIN = 4612;
const INPS_COMM_RATE = 0.2448;
const INPS_COMM_MIN_REDDITO = 18808;
const ROYALTY_ABBATT = 0.25;
const FRINGE_AUTO_ELECTRIC = 0.10;
const FRINGE_AUTO_BENZINA = 0.30;
const IRPEF_RATES = [
  { limit: 28000, rate: 0.23 },
  { limit: 50000, rate: 0.35 },
  { limit: Infinity, rate: 0.43 },
];

const FRINGE_OPTIONS = [
  { id: "auto_el", name: "Auto Elettrica", taxable: 0.10, max: 50000, icon: "🚗" },
  { id: "auto_ben", name: "Auto Benzina/Diesel", taxable: 0.30, max: 40000, icon: "🚙" },
  { id: "buoni", name: "Buoni Pasto", taxable: 0, max: 2500, note: "€4/giorno esente", icon: "🍽️" },
  { id: "smartphone", name: "Smartphone/Aziendale", taxable: 0, max: 1000, note: "spesso esente", icon: "📱" },
  { id: "abbonamenti", name: "Abbonamenti (palestra, etc)", taxable: 0, max: 1500, note: "spesso esente", icon: "💪" },
];

function irpef(reddito) {
  if (reddito <= 0) return 0;
  let tax = 0, prev = 0;
  for (const { limit, rate } of IRPEF_RATES) {
    const taxable = Math.min(reddito, limit) - prev;
    if (taxable <= 0) break;
    tax += taxable * rate;
    prev = limit;
  }
  return tax;
}

function fmt(n) {
  const sign = n < 0 ? "−" : "";
  return sign + "€" + Math.abs(Math.round(n)).toLocaleString("it-IT");
}

function calcSoloForfettario(torta) {
  const f_reddito = torta * COEFF;
  const f_inps = f_reddito * INPS_GS;
  const f_base = Math.max(f_reddito - f_inps, 0);
  const f_tax = f_base * FORF_TAX;
  const f_net = torta - f_inps - f_tax;
  return {
    nome: "Solo Forfettario", canali: ["Fattura"], net: f_net, dichiarato: f_base, taxes: f_inps + f_tax,
    detail: { fattura: { gross: torta, tax: f_inps + f_tax, net: f_net } }
  };
}

function calcForfettarioRoyalties(torta, royaltiesVal) {
  const R = royaltiesVal;
  const F = torta - R;
  const f_reddito = F * COEFF, f_inps = f_reddito * INPS_GS, f_base = Math.max(f_reddito - f_inps, 0), f_tax = f_base * FORF_TAX, f_net = F - f_inps - f_tax;
  const r_base = R * (1 - ROYALTY_ABBATT), r_tax = irpef(r_base), r_net = R - r_tax;
  return {
    nome: "Forfettario + Royalties", canali: ["Fattura", "Royalties"], net: f_net + r_net, dichiarato: f_base + r_base, taxes: f_inps + f_tax + r_tax,
    detail: { fattura: { gross: F, tax: f_inps + f_tax, net: f_net }, royalties: { gross: R, tax: r_tax, net: r_net } }
  };
}

function calcSocioLavForfettario(torta, quotaPct, utileSRL) {
  const F = torta;
  const f_reddito = F * COEFF, f_inps = f_reddito * INPS_GS, f_base = Math.max(f_reddito - f_inps, 0), f_tax = f_base * FORF_TAX, f_net = F - f_inps - f_tax;
  const quotaUtile = utileSRL * (quotaPct / 100);
  let inps_comm = INPS_COMM_MIN;
  if (quotaUtile > INPS_COMM_MIN_REDDITO) inps_comm += (quotaUtile - INPS_COMM_MIN_REDDITO) * INPS_COMM_RATE;
  const dividendoLordo = quotaUtile * 0.5, dividendoNetto = dividendoLordo * 0.74;
  return {
    nome: "Socio Lav. + Forfettario", canali: ["Fattura", "Dividendi"], net: f_net + dividendoNetto - inps_comm, dichiarato: f_base + dividendoLordo * 0.74, taxes: f_inps + f_tax + inps_comm,
    detail: { fattura: { gross: F, tax: f_inps + f_tax, net: f_net }, inps_comm, dividendi: { gross: dividendoLordo, net: dividendoNetto } }
  };
}

function calcSocioAmmNoComp(torta, quotaPct, utileSRL, fringeTot) {
  const F = torta - fringeTot;
  const f_reddito = F * COEFF, f_inps = f_reddito * INPS_GS, f_base = Math.max(f_reddito - f_inps, 0), f_tax = f_base * FORF_TAX, f_net = F - f_inps - f_tax;
  
  let totalFringeTax = 0;
  let fringeNet = 0;
  for (const f of fringeOptions) {
    if (f.value > 0) {
      const taxable = f.value * f.taxable;
      const tax = irpef(taxable);
      totalFringeTax += tax;
      fringeNet += f.value - tax;
    }
  }
  
  const quotaUtile = utileSRL * (quotaPct / 100);
  let inps_comm = INPS_COMM_MIN;
  if (quotaUtile > INPS_COMM_MIN_REDDITO) inps_comm += (quotaUtile - INPS_COMM_MIN_REDDITO) * INPS_COMM_RATE;
  const dividendoLordo = quotaUtile * 0.5, dividendoNetto = dividendoLordo * 0.74;
  return {
    nome: "Socio + Amm. + Fringe", canali: ["Fattura", "Fringe", "Dividendi"], net: f_net + dividendoNetto + fringeNet - inps_comm, dichiarato: f_base + fringeTot * 0.1 + dividendoLordo * 0.74, taxes: f_inps + f_tax + totalFringeTax + inps_comm,
    detail: { fattura: { gross: F, tax: f_inps + f_tax, net: f_net }, fringe: { gross: fringeTot, tax: totalFringeTax, net: fringeNet }, inps_comm, dividendi: { gross: dividendoLordo, net: dividendoNetto } }
  };
}

function calcSocioAmmConComp(torta, quotaPct, utileSRL, fringeTot, compVal) {
  const C = compVal;
  const F = torta - C - fringeTot;
  let f_reddito = 0, f_inps = 0, f_base = 0, f_tax = 0, f_net = 0;
  if (F > 0) { f_reddito = F * COEFF; f_inps = f_reddito * INPS_GS; f_base = Math.max(f_reddito - f_inps, 0); f_tax = f_base * FORF_TAX; f_net = F - f_inps - f_tax; }
  const c_base = C, c_irpef = irpef(c_base), c_inps = C * INPS_GS, c_net = C - c_irpef - c_inps;
  
  let totalFringeTax = 0;
  let fringeNet = 0;
  for (const f of fringeOptions) {
    if (f.value > 0) {
      const taxable = f.value * f.taxable;
      const tax = irpef(taxable);
      totalFringeTax += tax;
      fringeNet += f.value - tax;
    }
  }
  
  const quotaUtile = utileSRL * (quotaPct / 100);
  let inps_comm = INPS_COMM_MIN;
  if (quotaUtile > INPS_COMM_MIN_REDDITO) inps_comm += (quotaUtile - INPS_COMM_MIN_REDDITO) * INPS_COMM_RATE;
  const dividendoLordo = quotaUtile * 0.5, dividendoNetto = dividendoLordo * 0.74;
  return {
    nome: "Socio + Amm.+Comp", canali: ["Compenso", "Fattura", "Dividendi"], net: f_net + c_net + dividendoNetto + fringeNet - inps_comm, dichiarato: f_base + c_base + fringeTot * 0.1 + dividendoLordo * 0.74, taxes: f_inps + f_tax + c_irpef + c_inps + totalFringeTax + inps_comm,
    detail: { compenso: { gross: C, tax: c_irpef + c_inps, net: c_net }, fattura: F > 0 ? { gross: F, tax: f_inps + f_tax, net: f_net } : null, fringe: { gross: fringeTot, tax: totalFringeTax, net: fringeNet }, inps_comm, dividendi: { gross: dividendoLordo, net: dividendoNetto } }
  };
}

let fringeOptions = [];
let fringeValues = [];

const COLORS = { A: "#6366f1", B: "#f59e0b", C: "#10b981", D: "#ec4899", E: "#8b5cf6" };

function Slider({ label, value, onChange, min, max, step, format = fmt, color = "#4f46e5", note }) {
  const pctValue = ((value - min) / (max - min)) * 100;
  return (
    <div style={{ marginBottom: 16 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 6 }}>
        <span style={{ fontSize: 13, fontWeight: 500, color: "#374151" }}>{label}</span>
        <span style={{ fontSize: 18, fontWeight: 700, color }}>{format(value)}</span>
      </div>
      <input type="range" min={min} max={max} step={step} value={value} onChange={e => onChange(Number(e.target.value))} style={{ width: "100%" }} />
      {note && <div style={{ fontSize: 10, color: "#9ca3af", marginTop: 4 }}>{note}</div>}
    </div>
  );
}

